B.On=new A.aO("dsl_binary_mod3","Binary Mod 3","Build a DFA over {0,1} that accepts binary strings whose value is divisible by 3 (i.e. binary mod 3 = 0). Reading a 0 doubles the current remainder; reading a 1 doubles it and adds 1.","      n0 = 0\n      n1 = 1\n      n2 = 2\n      n0 = (538.7, 187.3)\n      n1 = (1036.7, 342.0)\n      n2 = (670.0, 578.7)\n      n0 is accepted\n      n0 to n1 = 1\n      n1 to n0 = 1\n      n0 to n0 = 0\n      n1 to n2 = 0\n      n2 to n1 = 0\n      n2 to n2 = 1\n      l0(1) curve = 75.9\n      l1(1) curve = 79.5\n      l3(0) curve = 91.1\n      l4(0) curve = 25.3\n      l2(0) loop angle = -1.5708\n      l5(1) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,B.aC,B.dk,B.a_0,0.5,"dfa",!1,B.H,!1,null,B.M,"",!1)
