B.Oe=new A.aO("dsl_binary_mod7","Binary Mod 7","Build a DFA over {0,1} that accepts binary strings whose value is divisible by 7 (binary mod 7 = 0). States 0\u20136 represent the current remainder.","      n0 = 0\n      n1 = 1\n      n2 = 2\n      n3 = 3\n      n4 = 4\n      n5 = 5\n      n6 = 6\n      n0 = (640.0, 92.6)\n      n1 = (1112.0, 196.0)\n      n2 = (1560.0, 282.7)\n      n3 = (250.0, 223.3)\n      n4 = (929.3, 422.7)\n      n5 = (645.3, 592.7)\n      n6 = (303.3, 518.7)\n      n0 is accepted\n      n0 to n1 = 1\n      n0 to n0 = 0\n      n1 to n2 = 0\n      n1 to n3 = 1\n      n3 to n6 = 0\n      n3 to n0 = 1\n      n2 to n5 = 1\n      n2 to n4 = 0\n      n4 to n1 = 0\n      n4 to n2 = 1\n      n5 to n3 = 1\n      n5 to n4 = 1\n      n6 to n5 = 0\n      n6 to n6 = 1\n      l3(1) curve = 21.0\n      l4(0) curve = -194.4\n      l5(1) curve = 34.0\n      l6(1) curve = 316.5\n      l7(0) curve = 152.5\n      l8(0) curve = 17.9\n      l9(1) curve = -15.5\n      l10(1) curve = 15.0\n      l11(1) curve = -59.2\n      l1(0) loop angle = -1.5708\n      l13(1) loop angle = -1.5708\n      to n0\n      to n0 length = 150.3\n      to n0 angle = -0.8423, -0.5390\n    ",B.E,null,B.dk,B.DZ,0.25,"boss",!1,B.H,!0,null,B.M,"",!1)
B.P0=new A.aO("dsl_binary_mod8","Binary Mod 8","Build a DFA over {0,1} that accepts binary strings whose value is divisible by 8 (binary mod 8 = 0). States 0\u20137 represent the current remainder.","      n0 = 0\n      n1 = 1\n      n2 = 2\n      n3 = 3\n      n4 = 4\n      n5 = 5\n      n6 = 6\n      n7 = 7\n      n0 = (338.0, 209.3)\n      n1 = (715.3, 212.0)\n      n2 = (432.0, 446.7)\n      n3 = (1418.7, 219.3)\n      n4 = (167.3, 640.7)\n      n5 = (585.3, 610.0)\n      n6 = (870.0, 627.3)\n      n7 = (1173.3, 622.0)\n      n0 is accepted\n      n0 to n0 = 0\n      n0 to n1 = 1\n      n1 to n3 = 1\n      n1 to n2 = 0\n      n2 to n4 = 0\n      n4 to n0 = 0\n      n4 to n1 = 1\n      n2 to n5 = 1\n      n5 to n2 = 0\n      n5 to n3 = 1\n      n3 to n6 = 0\n      n3 to n7 = 1\n      n7 to n6 = 0\n      n7 to n7 = 1\n      n6 to n4 = 0\n      n6 to n5 = 1\n      l6(1) curve = 439.5\n      l7(1) curve = 30.8\n      l8(0) curve = 16.7\n      l14(0) curve = 126.4\n      l0(0) loop angle = -1.5708\n      l13(1) loop angle = 0.4628\n      to n0\n      to n0 length = 114.5\n      to n0 angle = -0.9767, -0.2148\n    ",B.E,null,B.dk,B.DZ,0.75,"boss",!1,B.H,!0,null,B.M,"",!1)
