B.a7Q=new A.hv(7,"pdaStack")
B.a8d=new A.dt("Beyond Finite Memory","Some languages **cannot** be recognised by a DFA or NFA. The classic example is a\u207fb\u207f \u2014 equal numbers of a's then b's.\n\nA DFA has no memory of how many a's it has seen. A **PDA** adds a **stack** \u2014 an infinite scratchpad \u2014 which solves this.",B.a7Q)
B.a8f=new A.dt("PDA Transition Format",'Each PDA transition arrow has the label format:\n\n  **read, pop | push**\n\n\u2022 **read** \u2014 the input symbol consumed (**~** means consume nothing)\n\u2022 **pop**  \u2014 the stack symbol removed from the top (**~** means pop nothing)\n\u2022 **push** \u2014 the stack symbol added on top (**~** means push nothing)\n\nExample: **"a, ~ | X"** \u2014 read "a", don\'t pop, push "X".',B.bY)
B.a81=new A.dt("Stack Strategy for a\u207fb\u207f",'Here\'s the classic approach for equal-count problems:\n\n1. **Push** a marker (e.g. X) for each "a" you read.\n2. When you start reading "b"s, **pop** one X per "b".\n3. Accept when the stack is empty and input is exhausted.\n\nIf the stack runs out before the input (or vice versa), the counts don\'t match \u2014 reject.',B.bY)
B.S7=s([B.a8d,B.a8f,B.a81],t.nY)
B.OO=new A.aO("tutorial_pda","Pushdown Automata","Learn how PDAs use a stack to recognise context-free languages.","",B.E,null,B.bE,B.ZY,0.5,"tutorial",!0,B.S7,!1,null,B.M,"",!1)
B.W5={'"Green Leaf"':0,"(others)":1}
B.a0p=new A.e2(B.W5,2,t.fF)
