B.OI=new A.aO("dsl_caterpillar_nfa","Hungry Caterpillar (NFA)",'The Very Hungry Caterpillar ends by eating EXACTLY one "Green Leaf".\nBuild an NFA over story words where .-"Green Leaf" means "every word except Green Leaf". Accept strings whose last food item is exactly one Green Leaf.','      n0 = A\n      n1 = B\n      n0 = (689.3, 458.7)\n      n1 = (1080.7, 454.7)\n      n1 is accepted\n      n0 to n1 = "Green Leaf"\n      n0 to n0 = .-"Green Leaf"\n      .-"Green Leaf" loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ',B.E,B.bD,B.a0p,B.E0,0.2,"nfa",!1,B.H,!1,null,B.M,"",!1)
