B.Oa=new A.aO("pda_balanced_parens","Balanced Parentheses",'Build a PDA over {(, )} that accepts strings with balanced parentheses (e.g. "(()())" accepted, "(()" rejected).\nPush a marker on every "(" and pop it on every ")".',"      pda mode\n      n0 = A\n      n1 = B\n      n0 = (480.0, 360.0)\n      n1 = (820.0, 360.0)\n      n0 is accepted\n      n0 to n0 = (,\u2205|X\n      n0 to n1 = ),X|\u2205\n      n1 to n1 = ),X|\u2205\n      n1 to n0 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aU,null,B.a0u,B.ZZ,0.5,"pda",!1,B.H,!1,null,B.M,"",!1)
