B.P8=new A.aO("pda_anbn","a\u207fb\u207f","Build a PDA that accepts exactly strings of the form a\u207fb\u207f (n \u2265 1): the same number of a's followed by the same number of b's.\nClassic context-free language \u2014 not recognisable by any DFA!","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|X\n      n0 to n1 = b,X|\u2205\n      n1 to n1 = b,X|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aU,null,B.ae,B.a_p,0.5,"pda",!1,B.H,!1,null,B.M,"",!1)
