B.OJ=new A.aO("pda_more_as","More a's Than b's","Build a PDA over {a, b} that accepts strings where the number of a's is strictly greater than the number of b's (in any order).\nPush for each a, pop for each b; accept if the stack is non-empty at the end.","      pda mode\n      n0 = A\n      n1 = B\n      n0 = (380.0, 360.0)\n      n1 = (720.0, 360.0)\n      n0 to n0 = a,\u2205|X\n      n0 to n0 = b,X|\u2205\n      n0 to n1 = \u2205,X|X\n      n1 is accepted\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aU,null,B.ae,B.a_o,0.5,"pda",!1,B.H,!1,null,B.M,"",!1)
B.a_q=new A.c9("pda_more_as")
B.Oo=new A.aO("pda_an_b2n","a\u207fb\xb2\u207f","Build a PDA that accepts strings of the form a\u207fb\xb2\u207f (n \u2265 1): for every a there must be exactly two b's.\nHint: push two markers for each a you read.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|X\n      n0 to n0 = a,\u2205|X\n      n0 to n1 = b,X|\u2205\n      n1 to n1 = b,X|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aU,null,B.ae,B.a_q,0.5,"pda",!1,B.H,!1,null,B.M,"",!1)
