B.a_1=new A.ft(B.Tp)
B.a7R=new A.hv(8,"tmTape")
B.a7X=new A.dt("The Turing Machine","A Turing machine adds a **read/write tape** to a finite automaton. The tape is infinite in both directions and starts with your input.\n\nA **read/write head** sits on one cell at a time. On each step it reads the current symbol, writes a new symbol (or leaves it), and moves **Left** or **Right** (or stays Still).",B.a7R)
B.a7W=new A.dt("TM Transition Format",'Each TM arrow label has the format:\n\n  **readSymbol writeSymbol Direction**\n\nDirection is **R** (right), **L** (left), or **S** (stay).\n\nExample: **"aXR"** \u2014 read "a", write "X", move Right.\nExample: **"\u2205\u2205S"** \u2014 read blank, write blank, stay (blank = empty cell).',B.bY)
B.a8g=new A.dt("Accepting and Rejecting","A TM **accepts** by entering an accept state (double ring) and halting.\n\nA TM **rejects** either by entering a reject state (no outgoing transition for the current symbol causes a crash) or by looping forever.\n\nThe equivalence checker uses a bounded simulation \u2014 it tests many input strings but can't always prove correctness on all inputs.",B.bY)
B.a87=new A.dt("The Crossout Technique",'Many TM puzzles use a **crossout** strategy:\n\n1. Replace a matched symbol with **X** (or another marker) to "cross it out".\n2. Sweep the tape left/right to find the next unmatched symbol.\n3. Repeat until all symbols are matched or a mismatch is detected.\n\nYou\'ll see this in a\u207fb\u207f, a\u207fb\u207fc\u207f, palindrome, and the "ww" puzzles.',B.bY)
B.a7Z=new A.dt("Multiple Loops on One State","TM states often have **many self-loops** \u2014 one for each symbol the machine should pass over without stopping.\n\nIn the canvas you can drag a self-loop's label dot to rotate it around the state circle, so diagrams stay readable even with 4\u20135 loops on one state.",B.bY)
B.Tg=s([B.a7X,B.a7W,B.a8g,B.a87,B.a7Z],t.nY)
B.OM=new A.aO("tutorial_tm","Turing Machines","Learn the read/write tape model and TM transition format.","",B.E,null,B.bE,B.a_1,0.5,"tutorial",!0,B.Tg,!1,null,B.M,"",!1)
B.E1=new A.c9("tutorial_tm")
B.Oj=new A.aO("tm_identity","TM: Accept All (Trivial)","Build the simplest possible Turing machine: one that accepts every input by halting immediately.\nA single state that is both start and accept will do it. TM transition format: readSymbol writeSymbol Direction (e.g. aBR = read a, write B, move Right).","      tm mode\n      n0 = A\n      A = (600.0, 360.0)\n      A is accepted\n      to A angle = -1.0000, 0.0000\n    ",B.b1,null,B.bE,B.E1,0.25,"tm",!1,B.H,!1,null,B.M,"",!1)
B.Or=new A.aO("tm_reject_all","TM: Reject All","Build a TM that loops forever on any non-empty input (rejects by non-halt) and accepts only the empty tape.\nHint: a start state with a self-loop on every symbol that moves right will spin forever.","      tm mode\n      n0 = A\n      n1 = B\n      A = (480.0, 360.0)\n      B = (820.0, 360.0)\n      B is accepted\n      A to B = \u2205\u2205S\n      to A angle = -1.0000, 0.0000\n    ",B.b1,null,B.bE,B.E1,0.75,"tm",!1,B.H,!1,null,B.M,"",!1)
B.Tz=s(["tm_identity","tm_reject_all"],t.s)
B.a__=new A.ho(B.Tz)
B.P1=new A.aO("tm_anbn","TM: a\u207fb\u207f","Build a TM that accepts exactly strings of the form a\u207fb\u207f (n \u2265 1). Classic TM exercise: repeatedly cross off one a and one b until both sides are exhausted.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      A = (260.0, 200.0)\n      B = (660.0, 200.0)\n      C = (1060.0, 200.0)\n      D = (660.0, 560.0)\n      E = (260.0, 560.0)\n      E is accepted\n      A to B = aXR\n      B to B = aXR\n      B to C = bXL\n      C to D = XXL\n      D to D = aXL\n      D to A = XXR\n      A to E = \u2205\u2205S\n      l1(aXR) loop angle = -1.5708\n      l3(XXL) loop angle = -1.5708\n      l4(aXL) loop angle = 1.5708\n      aXR curve = 80.0\n      bXL curve = 80.0\n      XXR curve = 80.0\n      to A angle = -1.0000, 0.0000\n    ",B.b1,null,B.bE,B.a__,0.5,"tm",!1,B.H,!1,null,B.M,"",!1)
B.a_r=new A.c9("tm_anbn")
B.Ot=new A.aO("tm_anbncn","TM: a\u207fb\u207fc\u207f","Build a TM that accepts strings of the form a\u207fb\u207fc\u207f (n \u2265 1).\nThis language is not context-free \u2014 no PDA can recognise it \u2014 but a TM can! Cross off one a, one b, and one c per pass.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (580.0, 200.0)\n      C = (900.0, 200.0)\n      D = (900.0, 540.0)\n      E = (580.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      B to B = aaR\n      B to B = XXR\n      B to C = bXR\n      C to C = bbR\n      C to C = XXR\n      C to D = cXL\n      D to D = bbL\n      D to D = ccL\n      D to D = XXL\n      D to E = aaL\n      E to E = aaL\n      E to E = bbL\n      E to E = ccL\n      E to E = XXL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(XXR) loop angle = -0.8000\n      l4(bbR) loop angle = -1.5708\n      l5(XXR) loop angle = -0.8000\n      l7(bbL) loop angle = 1.5708\n      l8(ccL) loop angle = 0.8000\n      l9(XXL) loop angle = 2.3000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.8000\n      l13(ccL) loop angle = 2.3000\n      l14(XXL) loop angle = 3.1000\n      aXR curve = 70.0\n      bXR curve = 70.0\n      cXL curve = 70.0\n      aaL_E curve = 60.0\n      XXR_E curve = 60.0\n      to A angle = -1.0000, 0.0000\n    ",B.b1,null,B.bE,B.a_r,0.5,"tm",!1,B.H,!1,null,B.M,"",!1)
B.a_s=new A.c9("tm_anbncn")
B.Ox=new A.aO("tm_ww","TM: ww (Doubled Word)",'Build a TM that accepts strings of the form ww over {a, b}: a string that consists of some word w repeated exactly twice (e.g. "abab", "aabb aabb"). This is a classic non-context-free language.',"      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 180.0)\n      B = (660.0, 180.0)\n      C = (1060.0, 180.0)\n      D = (1060.0, 540.0)\n      E = (660.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to D = bXL\n      C to C = aaR\n      C to C = bbR\n      C to E = aXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.8000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.8000\n      l7(aaL) loop angle = 1.5708\n      l8(bbL) loop angle = 0.8000\n      l10(aaL) loop angle = 1.5708\n      l11(bbL) loop angle = 0.8000\n      aXR curve = 60.0\n      bXR curve = -60.0\n      bXL curve = 60.0\n      aXL curve = -60.0\n      XXR_D curve = 80.0\n      XXR_E curve = -80.0\n      to A angle = -1.0000, 0.0000\n    ",B.b1,null,B.bE,B.a_s,0.5,"tm",!1,B.H,!1,null,B.M,"",!1)
B.a_u=new A.c9("tm_ww")
B.OP=new A.aO("tm_palindrome","TM: Palindrome","Build a TM over {a, b} that accepts palindromes of any length.\nStrategy: repeatedly peel the first and last character and verify they match.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (640.0, 200.0)\n      C = (1020.0, 200.0)\n      D = (1020.0, 540.0)\n      E = (640.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to E = aXL\n      C to C = aaR\n      C to C = bbR\n      C to D = bXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.6000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.6000\n      l8(aaL) loop angle = 1.5708\n      l9(bbL) loop angle = 0.6000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.6000\n      aXR curve = 70.0\n      bXR curve = -70.0\n      aXL curve = -70.0\n      bXL curve = 70.0\n      to A angle = -1.0000, 0.0000\n    ",B.b1,null,B.bE,B.a_u,0.5,"tm",!1,B.H,!1,null,B.M,"",!1)
B.a_t=new A.c9("tm_palindrome")
B.a7Y=new A.dt("What is a Regular Expression?",'A **regular expression** (regex) is a compact notation for describing a regular language \u2014 the same class of languages recognised by DFAs and NFAs.\n\nOperators used in these puzzles:\n\u2022 **a** \u2014 literal symbol "a"\n\u2022 **ab** \u2014 concatenation (a then b)\n\u2022 **a+b** \u2014 alternation / union (a OR b)\n\u2022 **a*** \u2014 Kleene star (zero or more a)\n\u2022 **(\u2026)** \u2014 grouping',B.bY)
B.a8b=new A.dt("Regex \u2194 Automaton","Every regular expression describes exactly the same set of strings as some DFA (and vice versa). This is why they are called *regular* languages.\n\nThis section has two challenge types:\n\n**Regex \u2192 DFA** \u2014 You are given a regex and must build a DFA whose language matches it exactly.\n\n**DFA \u2192 Regex** \u2014 You are shown a read-only DFA diagram and must type a regex that describes the same language.",B.bY)
B.a83=new A.dt("Notation Reference",'The checker uses the following notation:\n\n\u2022 **~** \u2014 empty string \u03b5  (e.g. a+~ means "a or nothing")\n\u2022 **\u2205** \u2014 empty language (matches nothing)\n\u2022 **+** \u2014 alternation  (a+b means a OR b)\n\u2022 ***** \u2014 Kleene star, postfix  (a* = zero or more a)\n\u2022 Concatenation is implicit: **ab** means a then b\n\nPrecedence (high\u2192low): star \u2192 concat \u2192 union.\nUse parentheses to override: (a+b)* = any string over {a,b}.',B.bY)
B.a82=new A.dt("Tips: Regex \u2192 DFA",'When you see a regex, ask: "what pattern must a string satisfy?"\n\n\u2022 **ab*** \u2014 any number of b\'s after exactly one a\n\u2022 **(a+b)*abb** \u2014 anything, ending in "abb"\n\u2022 **(ab)*** \u2014 alternating pairs: \u03b5, ab, abab, \u2026\n\nThink about what the machine must *remember*. Each memory unit (e.g. "last symbol seen") usually becomes a state.',B.bY)
B.a7J=new A.hv(11,"addSuperStates")
B.a8e=new A.dt("DFA \u2192 Regex: Add Super States","To turn a DFA into a regex, first convert it into a **GNFA** (generalised NFA) by adding two new states:\n\n\u2022 A **super-start** S, with a single \u03b5-edge into the original start state.\n\u2022 A **super-accept** F, with an \u03b5-edge in from every original accept state (if there's more than one, they all point to the same F).\n\nFrom this point on, only S and F count as start/accept \u2014 that frees every other state, including the old accept state(s), to be eliminated in the next step.",B.a7J)
B.a7K=new A.hv(12,"stateElimination")
B.a8h=new A.dt("DFA \u2192 Regex: Eliminate States","Now eliminate the remaining states one at a time until only S and F are left. To remove a state B sitting between neighbours A and C:\n\n1. **Star** its self-loop, if it has one \u2014 label b becomes b*.\n2. **Sandwich** that between the edge going in and the edge going out: a \xb7 b* \xb7 c.\n3. **Union** (+) that with whatever edge, if any, already ran directly from A to C.\n\nExample: A -a\u2192 B (self-loop b) -c\u2192 C collapses to one edge A \u2192 C labelled **ab*c**.\n\nRepeat for every remaining state. Whatever label ends up on the final S \u2192 F edge is your answer.\n\nShortcut: pattern recognition is often faster than working it out by hand \u2014 spot self-loops (\u2192 *), linear paths (\u2192 concat), branches (\u2192 +).",B.a7K)
B.So=s([B.a7Y,B.a8b,B.a83,B.a82,B.a8e,B.a8h],t.nY)
B.OA=new A.aO("tutorial_regex","Regular Expressions","Learn the connection between regular expressions and finite automata.","",B.E,null,B.bE,B.a_t,0.5,"tutorial",!0,B.So,!1,null,B.M,"",!1)
B.om=new A.c9("tutorial_regex")
B.ew=new A.Fe(1,"regexToDfa")
B.OS=new A.aO("regex_to_dfa_ab_star","Regex \u2192 DFA: ab*",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    ab*\n\nMatches "a" followed by any number of b\'s: "a", "ab", "abb", "abbb", \u2026',"      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 580.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n1 = b\n      n1 to n2 = a\n      n2 to n2 = a,b\n      l2(b) loop angle = -1.5708\n      l4(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,B.aC,B.ae,B.om,0.2,"regex",!1,B.H,!1,null,B.ew,"ab*",!1)
B.Oc=new A.aO("regex_to_dfa_starts_a","Regex \u2192 DFA: a(a+b)*",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    a(a+b)*\n\nMatches all strings that start with "a": "a", "aa", "ab", "aba", \u2026',"      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 580.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n1 = a,b\n      n2 to n2 = a,b\n      l2(a,b) loop angle = -1.5708\n      l3(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,B.aC,B.ae,B.om,0.5,"regex",!1,B.H,!1,null,B.ew,"a(a+b)*",!1)
B.Ok=new A.aO("regex_to_dfa_ends_b","Regex \u2192 DFA: (a+b)*b",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    (a+b)*b\n\nMatches all strings that end with "b": "b", "ab", "bb", "aab", \u2026',u.C,B.E,B.aC,B.ae,B.om,0.8,"regex",!1,B.H,!1,null,B.ew,"(a+b)*b",!1)
B.R4=s(["regex_to_dfa_ab_star","regex_to_dfa_starts_a","regex_to_dfa_ends_b"],t.s)
B.oj=new A.ft(B.R4)
B.Oh=new A.aO("regex_to_dfa_a_or_b_star","Regex \u2192 DFA: (a+b)*","Build a DFA over {a, b} equivalent to the regular expression:\n\n    (a+b)*\n\nMatches every string over {a, b} \u2014 including the empty string \u03b5.","      n0 = q0\n      n0 = (600.0, 360.0)\n      n0 is accepted\n      n0 to n0 = a,b\n      a,b loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,B.aC,B.ae,B.oj,0.2,"regex",!1,B.H,!1,null,B.ew,"(a+b)*",!1)
B.P_=new A.aO("regex_to_dfa_aba","Regex \u2192 DFA: (a+b)*aba(a+b)*",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    (a+b)*aba(a+b)*\n\nMatches all strings containing "aba" as a substring.',"      n0 = q0\n      n1 = q1\n      n2 = q2\n      n3 = q3\n      n0 = (280.0, 360.0)\n      n1 = (580.0, 360.0)\n      n2 = (880.0, 360.0)\n      n3 = (1180.0, 360.0)\n      n3 is accepted\n      n0 to n1 = a\n      n0 to n0 = b\n      n1 to n1 = a\n      n1 to n2 = b\n      n2 to n3 = a\n      n3 to n3 = a,b\n      n2 to n0 = b\n      l0(b) loop angle = -1.5708\n      l2(a) loop angle = -1.5708\n      l5(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,B.aC,B.ae,B.oj,0.5,"regex",!1,B.H,!1,null,B.ew,"(a+b)*aba(a+b)*",!1)
B.Ov=new A.aO("regex_to_dfa_even_as","Regex \u2192 DFA: b*(ab*ab*)*","Build a DFA over {a, b} equivalent to the regular expression:\n\n    b*(ab*ab*)*\n\nMatches all strings with an even number of a's (including zero a's).",u.m,B.E,B.aC,B.ae,B.oj,0.8,"regex",!1,B.H,!1,null,B.ew,"b*(ab*ab*)*",!1)
B.Tf=s(["regex_to_dfa_a_or_b_star","regex_to_dfa_aba","regex_to_dfa_even_as"],t.s)
B.ok=new A.ft(B.Tf)
B.cE=new A.Fe(2,"dfaToRegex")
B.O8=new A.aO("dfa_to_regex_single_a",'DFA \u2192 Regex: Accept "a"','A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts only the single-character string "a".',"      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 580.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n2 = a,b\n      n2 to n2 = a,b\n      l3(a,b) loop angle = -1.5708\n      l2(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,null,B.ae,B.ok,0.2,"regex",!1,B.H,!1,null,B.cE,"a",!1)
B.Oi=new A.aO("dfa_to_regex_ends_b","DFA \u2192 Regex: Ends with b",'A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} that end with "b".',u.C,B.E,null,B.ae,B.ok,0.5,"regex",!1,B.H,!1,null,B.cE,"(a+b)*b",!1)
B.Og=new A.aO("dfa_to_regex_even_as","DFA \u2192 Regex: Even a's","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} with an even number of a's.",u.m,B.E,null,B.ae,B.ok,0.8,"regex",!1,B.H,!1,null,B.cE,"b*(ab*ab*)*",!1)
B.Sy=s(["dfa_to_regex_single_a","dfa_to_regex_ends_b","dfa_to_regex_even_as"],t.s)
B.ol=new A.ft(B.Sy)
B.OE=new A.aO("dfa_to_regex_starts_ab","DFA \u2192 Regex: Starts with ab",'A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} that start with "ab".',"      n0 = q0\n      n1 = q1\n      n2 = q2\n      n3 = dead\n      n0 = (240.0, 360.0)\n      n1 = (560.0, 360.0)\n      n2 = (880.0, 360.0)\n      n3 = (560.0, 600.0)\n      n2 is accepted\n      n0 to n1 = a\n      n0 to n3 = b\n      n1 to n2 = b\n      n1 to n3 = a\n      n2 to n2 = a,b\n      n3 to n3 = a,b\n      l4(a,b) loop angle = -1.5708\n      l5(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,null,B.ae,B.ol,0.2,"regex",!1,B.H,!1,null,B.cE,"ab(a+b)*",!1)
B.OX=new A.aO("dfa_to_regex_no_consec_b","DFA \u2192 Regex: No Consecutive b's","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} containing no two consecutive b's.","      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (400.0, 340.0)\n      n1 = (780.0, 340.0)\n      n2 = (580.0, 580.0)\n      n0 is accepted\n      n1 is accepted\n      n0 to n1 = b\n      n0 to n0 = a\n      n1 to n0 = a\n      n1 to n2 = b\n      n2 to n2 = a,b\n      l0(a) loop angle = -1.5708\n      l4(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,null,B.ae,B.ol,0.5,"regex",!1,B.H,!1,null,B.cE,"a*(ba+)*b?",!1)
B.OZ=new A.aO("dfa_to_regex_binary_mod2","DFA \u2192 Regex: Even 0s","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts binary strings over {0, 1} with an even number of 0s.","      n0 = even\n      n1 = odd\n      n0 = (504.7, 310.0)\n      n1 = (1030.0, 314.0)\n      n0 is accepted\n      n0 to n1 = 0\n      n1 to n0 = 0\n      n0 to n0 = 1\n      n1 to n1 = 1\n      l0(0) curve = -74.1\n      l1(0) curve = -72.7\n      l2(1) loop angle = -1.5708\n      l3(1) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,null,B.dk,B.ol,0.8,"regex",!1,B.H,!1,null,B.cE,"1*(01*01*)*",!1)
